                <div className="user-profile__action-button-content">
                  Kustuta kohalikud andmed
                </div>
              </button>

              <button
                onClick={handleLogout}
                className="user-profile__action-button user-profile__action-button--danger"
              >
                <div className="user-profile__action-button-content">
                  Logi välja
                </div>
              </button>
            </div>
          </div>
        </>
      )}
    </div>
  );
}

