            >
              Lisa ülesandesse ({sentenceCount})
            </button>
            <AddToTaskDropdown
              isOpen={showDropdown}
              onClose={onDropdownClose}
              onSelectTask={onSelectTask}
              onCreateNew={onCreateNew}
            />
          </div>
        )}
        {sentenceCount > 1 && (
          <PlayAllButton
            isPlaying={isPlayingAll}
            isLoading={isLoadingPlayAll}
            onClick={onPlayAllClick}
          />
        )}
      </div>
    </div>
  );
}

