    it("renders title input", () => {
      render(
        <AddEntryModal isOpen={true} onClose={mockOnClose} onAdd={mockOnAdd} />,
      );
      expect(
        screen.getByPlaceholderText("Pealkiri (Kohustuslik)"),
      ).toBeInTheDocument();
