/* eslint-disable max-lines, max-lines-per-function */
import { describe, it, expect, vi, beforeEach } from "vitest";
import { render, screen, waitFor } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import TaskEditModal from "./TaskEditModal";

describe("TaskEditModal", () => {
  const mockOnClose = vi.fn();
  const mockOnSave = vi.fn();
  const mockSetTaskToEdit = vi.fn();
  const mockTask = {
    id: "task-1",
    name: "Test Task",
    description: "Test description",
  };

  beforeEach(() => {
    vi.clearAllMocks();
    mockOnSave.mockResolvedValue(undefined);
  });

  describe("rendering", () => {
    it("returns null when not open", () => {
      const { container } = render(
        <TaskEditModal
          isOpen={false}
          task={mockTask}
          onClose={mockOnClose}
          onSave={mockOnSave}
          setTaskToEdit={mockSetTaskToEdit}
        />,
      );
      expect(container.firstChild).toBeNull();
    });

    it("returns null when no task", () => {
      const { container } = render(
        <TaskEditModal
          isOpen={true}
          task={null}
          onClose={mockOnClose}
          onSave={mockOnSave}
          setTaskToEdit={mockSetTaskToEdit}
        />,
      );
      expect(container.firstChild).toBeNull();
    });

    it("renders when open with task", () => {
      render(
        <TaskEditModal
          isOpen={true}
          task={mockTask}
          onClose={mockOnClose}
          onSave={mockOnSave}
          setTaskToEdit={mockSetTaskToEdit}
        />,
      );
      expect(screen.getByText("Muuda ülesannet")).toBeInTheDocument();
    });

    it("populates name field with task name", () => {
      render(
        <TaskEditModal
          isOpen={true}
          task={mockTask}
          onClose={mockOnClose}
          onSave={mockOnSave}
          setTaskToEdit={mockSetTaskToEdit}
        />,
      );
      expect(
        screen.getByPlaceholderText("Ülesande nimi (Kohustuslik)"),
      ).toHaveValue("Test Task");
    });

    it("populates description field with task description", () => {
      render(
        <TaskEditModal
          isOpen={true}
          task={mockTask}
          onClose={mockOnClose}
          onSave={mockOnSave}
          setTaskToEdit={mockSetTaskToEdit}
        />,
      );
      expect(screen.getByPlaceholderText("Kirjeldus")).toHaveValue(
        "Test description",
      );
    });

    it("handles task without description", () => {
      const taskNoDesc = { id: "task-1", name: "Test Task" };
      render(
        <TaskEditModal
          isOpen={true}
          task={taskNoDesc}
          onClose={mockOnClose}
          onSave={mockOnSave}
          setTaskToEdit={mockSetTaskToEdit}
        />,
      );
      expect(screen.getByPlaceholderText("Kirjeldus")).toHaveValue("");
    });

    it("renders submit button", () => {
      render(
        <TaskEditModal
          isOpen={true}
          task={mockTask}
          onClose={mockOnClose}
          onSave={mockOnSave}
          setTaskToEdit={mockSetTaskToEdit}
        />,
      );
      expect(
        screen.getByRole("button", { name: "Salvesta" }),
      ).toBeInTheDocument();
    });
  });

  describe("input handling", () => {
    it("updates name on input", async () => {
      const user = userEvent.setup();
      render(
        <TaskEditModal
          isOpen={true}
          task={mockTask}
          onClose={mockOnClose}
          onSave={mockOnSave}
          setTaskToEdit={mockSetTaskToEdit}
        />,
      );

      const input = screen.getByPlaceholderText("Ülesande nimi (Kohustuslik)");
      await user.clear(input);
      await user.type(input, "New Name");
      expect(input).toHaveValue("New Name");
    });

    it("updates description on input", async () => {
      const user = userEvent.setup();
      render(
        <TaskEditModal
          isOpen={true}
          task={mockTask}
          onClose={mockOnClose}
          onSave={mockOnSave}
          setTaskToEdit={mockSetTaskToEdit}
        />,
      );

      const textarea = screen.getByPlaceholderText("Kirjeldus");
      await user.clear(textarea);
      await user.type(textarea, "New Description");
      expect(textarea).toHaveValue("New Description");
    });

    it("disables submit with empty name", async () => {
      const user = userEvent.setup();
      render(
        <TaskEditModal
          isOpen={true}
          task={mockTask}
          onClose={mockOnClose}
          onSave={mockOnSave}
          setTaskToEdit={mockSetTaskToEdit}
        />,
      );

      const input = screen.getByPlaceholderText("Ülesande nimi (Kohustuslik)");
      await user.clear(input);
      expect(screen.getByRole("button", { name: "Salvesta" })).toBeDisabled();
    });
  });

  describe("form submission", () => {
    it("calls setTaskToEdit with trimmed values and onSave", async () => {
      const user = userEvent.setup();
      render(
        <TaskEditModal
          isOpen={true}
          task={mockTask}
          onClose={mockOnClose}
          onSave={mockOnSave}
          setTaskToEdit={mockSetTaskToEdit}
        />,
      );

      const input = screen.getByPlaceholderText("Ülesande nimi (Kohustuslik)");
      await user.clear(input);
      await user.type(input, "  New Name  ");
      await user.click(screen.getByRole("button", { name: "Salvesta" }));

      await waitFor(() => {
        expect(mockSetTaskToEdit).toHaveBeenCalledWith({
          id: "task-1",
          name: "New Name",
          description: "Test description",
        });
        expect(mockOnSave).toHaveBeenCalled();
      });
    });

    it("closes modal on successful save", async () => {
      const user = userEvent.setup();
      render(
        <TaskEditModal
          isOpen={true}
          task={mockTask}
          onClose={mockOnClose}
          onSave={mockOnSave}
          setTaskToEdit={mockSetTaskToEdit}
        />,
      );

      await user.click(screen.getByRole("button", { name: "Salvesta" }));

      await waitFor(() => {
        expect(mockOnClose).toHaveBeenCalled();
      });
    });

    it("shows loading state during save", async () => {
      mockOnSave.mockImplementation(
        () => new Promise((resolve) => setTimeout(resolve, 100)),
      );
      const user = userEvent.setup();
      render(
        <TaskEditModal
          isOpen={true}
          task={mockTask}
          onClose={mockOnClose}
          onSave={mockOnSave}
          setTaskToEdit={mockSetTaskToEdit}
        />,
      );

      await user.click(screen.getByRole("button", { name: "Salvesta" }));

      expect(screen.getByText("Salvestan...")).toBeInTheDocument();
    });

    it("disables inputs during save", async () => {
      mockOnSave.mockImplementation(
        () => new Promise((resolve) => setTimeout(resolve, 100)),
      );
      const user = userEvent.setup();
      render(
        <TaskEditModal
          isOpen={true}
          task={mockTask}
          onClose={mockOnClose}
          onSave={mockOnSave}
          setTaskToEdit={mockSetTaskToEdit}
        />,
      );

      await user.click(screen.getByRole("button", { name: "Salvesta" }));

      expect(
        screen.getByPlaceholderText("Ülesande nimi (Kohustuslik)"),
      ).toBeDisabled();
      expect(screen.getByPlaceholderText("Kirjeldus")).toBeDisabled();
    });

    it("passes null for empty description", async () => {
      const user = userEvent.setup();
      render(
        <TaskEditModal
          isOpen={true}
          task={mockTask}
          onClose={mockOnClose}
          onSave={mockOnSave}
          setTaskToEdit={mockSetTaskToEdit}
        />,
      );

      const textarea = screen.getByPlaceholderText("Kirjeldus");
      await user.clear(textarea);
      await user.click(screen.getByRole("button", { name: "Salvesta" }));

      await waitFor(() => {
        expect(mockSetTaskToEdit).toHaveBeenCalledWith({
          id: "task-1",
          name: "Test Task",
          description: null,
        });
        expect(mockOnSave).toHaveBeenCalled();
      });
    });
  });

  describe("error handling", () => {
    it("shows error on save failure", async () => {
      mockOnSave.mockRejectedValue(new Error("Save failed"));
      const user = userEvent.setup();
      render(
        <TaskEditModal
          isOpen={true}
          task={mockTask}
          onClose={mockOnClose}
          onSave={mockOnSave}
          setTaskToEdit={mockSetTaskToEdit}
        />,
      );

      await user.click(screen.getByRole("button", { name: "Salvesta" }));

      await waitFor(() => {
        expect(screen.getByText("Save failed")).toBeInTheDocument();
      });
    });

    it("shows generic error for non-Error rejection", async () => {
      mockOnSave.mockRejectedValue("unknown");
      const user = userEvent.setup();
      render(
        <TaskEditModal
          isOpen={true}
          task={mockTask}
          onClose={mockOnClose}
          onSave={mockOnSave}
          setTaskToEdit={mockSetTaskToEdit}
        />,
      );

      await user.click(screen.getByRole("button", { name: "Salvesta" }));

      await waitFor(() => {
        expect(screen.getByText("Viga ülesande muutmisel")).toBeInTheDocument();
      });
    });

    it.skip("does not close on error", async () => {
      mockOnSave.mockRejectedValue(new Error("Failed"));
      const user = userEvent.setup();
      render(
        <TaskEditModal
          isOpen={true}
          task={mockTask}
          onClose={mockOnClose}
          onSave={mockOnSave}
          setTaskToEdit={mockSetTaskToEdit}
        />,
      );

      await user.click(screen.getByRole("button", { name: "Salvesta" }));

      await waitFor(() => {
        expect(screen.getByText("Failed")).toBeInTheDocument();
      });
      expect(mockOnClose).not.toHaveBeenCalled();
    });
  });
});

