    it("renders all navigation links", () => {
      render(
        <MemoryRouter>
          <AppHeader {...defaultProps} />
        </MemoryRouter>,
      );
      expect(screen.getByText("Tekst kõneks")).toBeInTheDocument();
      expect(screen.getByText("Ülesanded")).toBeInTheDocument();
    });

    it("renders help button", () => {
