      render(
        <MemoryRouter>
          <AppHeader {...defaultProps} />
        </MemoryRouter>,
      );

      await user.click(screen.getByText("Logi sisse"));
      expect(mockOnLoginClick).toHaveBeenCalled();
    });
  });
});

