      render(
        <ShareTaskModal
          isOpen={true}
          shareToken="abc123"
          taskName="Test Task"
          onClose={mockOnClose}
        />,
      );
      expect(
        screen.getByRole("button", { name: "Kopeeri" }),
      ).toBeInTheDocument();
    });

    it("button is not disabled by default", () => {
      render(
        <ShareTaskModal
          isOpen={true}
          shareToken="abc123"
          taskName="Test Task"
          onClose={mockOnClose}
        />,
      );
      expect(
        screen.getByRole("button", { name: "Kopeeri" }),
      ).not.toBeDisabled();
    });
  });

  describe("copy functionality", () => {
    it("copy button is clickable", async () => {
      const user = userEvent.setup();
      render(
        <ShareTaskModal
          isOpen={true}
          shareToken="abc123"
          taskName="Test Task"
          onClose={mockOnClose}
